import{_ as e,c as o,o as l,ae as a}from"./chunks/framework.B7Y1jjX-.js";const p=JSON.parse('{"title":"一刻短剧项目文档","description":"","frontmatter":{},"headers":[],"relativePath":"notes/前端/项目笔记/短剧/视频播放.md","filePath":"notes/前端/项目笔记/短剧/视频播放.md"}'),i={name:"notes/前端/项目笔记/短剧/视频播放.md"};function r(s,t,n,d,g,c){return l(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="一刻短剧项目文档" tabindex="-1">一刻短剧项目文档 <a class="header-anchor" href="#一刻短剧项目文档" aria-label="Permalink to &quot;一刻短剧项目文档&quot;">​</a></h1><hr><h5 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h5><p>【整理自原内容】本项目是基于原生开发网站的二次开发，专注于短剧的竖屏播放体验。由于短剧的形态特性不适合传统H5布局，前端界面将全面模仿抖音的交互与视觉风格。</p><h5 id="技术栈说明" tabindex="-1">技术栈说明 <a class="header-anchor" href="#技术栈说明" aria-label="Permalink to &quot;技术栈说明&quot;">​</a></h5><p>【补充内容】项目前端主要采用现代Web技术栈：</p><ul><li><strong>核心框架</strong>：Vue.js（用于构建复杂用户界面和状态管理）</li><li><strong>播放器核心</strong>：Video.js（用于统一播放器UI和处理视频播放逻辑，强烈推荐）</li><li><strong>样式处理</strong>：CSS3、Sass、ElementPlus（用于实现全屏、flex布局、过渡动画等）</li><li><strong>构建工具</strong>：Vite（用于模块化开发和打包）</li><li><strong>HTTP客户端</strong>：Axios（用于与后端API交互）</li></ul><h5 id="api接口说明" tabindex="-1">API接口说明 <a class="header-anchor" href="#api接口说明" aria-label="Permalink to &quot;API接口说明&quot;">​</a></h5><p>【整理自原内容】后端API主要提供短剧相关内容及分类信息。API管理与测试使用<strong>Apifox</strong>工具，项目名称为“悦享好剧”。</p><p>【补充内容】需重点调用的API接口示例：</p><ul><li><code>GET /api/playlet/list</code>：获取短剧列表（分页）</li><li><code>GET /api/playlet/detail/{id}</code>：获取特定短剧的详情和剧集列表</li><li><code>GET /api/category</code>：获取分类列表</li></ul><h5 id="配色方案" tabindex="-1">配色方案 <a class="header-anchor" href="#配色方案" aria-label="Permalink to &quot;配色方案&quot;">​</a></h5><p>【整理自原内容】主色调采用 <code>#e84a5f</code>，辅助色为 <code>#fecea8</code>。 ![[Pasted image 20250829141401.png]]</p><p>【补充内容】配色应用指南：</p><ul><li><code>#e84a5f</code> (主色)：用于主要按钮、重要标签、点赞和关注等核心交互元素。</li><li><code>#fecea8</code> (辅助色)：用于背景高光、次要按钮或渐变效果的起点。</li><li><strong>建议扩展色板</strong>：可补充中性色（如 <code>#f5f5f5</code> 用于背景，<code>#333333</code> 用于主要文字，<code>#999999</code> 用于次要文字）以确保良好的可读性和层次感。</li></ul><h5 id="品牌标识" tabindex="-1">品牌标识 <a class="header-anchor" href="#品牌标识" aria-label="Permalink to &quot;品牌标识&quot;">​</a></h5><p>【整理自原内容】项目图标为“一刻短剧”Logo。 ![[一刻短剧.png]]</p><p>【补充内容】图标使用规范：</p><ul><li>** Favicon**：需将图标转换为 <code>.ico</code> 格式并设置为网站的favicon。</li><li><strong>应用图标</strong>：应准备多种尺寸（如 192x192, 512x512）以支持PWA（渐进式Web应用）的安装。</li><li><strong>显示位置</strong>：通常出现在首页的左上角、关于页面以及浏览器标签页上。</li></ul><h5 id="视频播放关键技术方案" tabindex="-1">视频播放关键技术方案 <a class="header-anchor" href="#视频播放关键技术方案" aria-label="Permalink to &quot;视频播放关键技术方案&quot;">​</a></h5><p>【整理并去重后的核心内容】服务器支持HTTP Range Requests (<code>206 Partial Content</code>)，可实现伪流媒体播放，这是实现流畅体验的基础。</p><p><strong>播放器选型分析：Video.js vs 原生Video标签</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">原生 <code>&lt;video&gt;</code> 标签</th><th style="text-align:left;">Video.js</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>UI一致性</strong></td><td style="text-align:left;">浏览器间样式不统一</td><td style="text-align:left;">提供统一、可定制的UI皮肤</td></tr><tr><td style="text-align:left;"><strong>功能与API</strong></td><td style="text-align:left;">基础API</td><td style="text-align:left;">扩展API与插件生态</td></tr><tr><td style="text-align:left;"><strong>兼容性</strong></td><td style="text-align:left;">依赖浏览器原生支持</td><td style="text-align:left;">填补格式支持差距（如HLS）</td></tr><tr><td style="text-align:left;"><strong>开发效率</strong></td><td style="text-align:left;">需手动处理细节</td><td style="text-align:left;">提供高级抽象，节省开发时间</td></tr></tbody></table><p><strong>推荐实现方案：</strong></p><ol><li><strong>播放核心</strong>：使用 <strong>Video.js</strong> 库，它封装了原生<code>&lt;video&gt;</code>标签，提供统一UI、强大API和更好的格式兼容性（例如，未来若支持HLS流，可无缝集成hls.js）。</li><li><strong>播放体验</strong>：利用服务器支持的 <code>Range Requests</code> 实现视频的快速启动、拖拽跳转和带宽节约。</li><li><strong>抖音式交互</strong>：实现上下滑动切换视频的核心组件。 <ul><li><strong>手势监听</strong>：使用 <code>touchstart</code>, <code>touchmove</code>, <code>touchend</code> 事件或 <code>hammer.js</code> 库监听滑动手势。</li><li><strong>视频管理</strong>：采用“三实例模型”，只维护<strong>当前</strong>、<strong>上一个</strong>、<strong>下一个</strong>三个视频元素，优化性能。</li><li><strong>预加载策略</strong>：预先加载下一个视频的元数据和部分数据，实现无缝切换。</li></ul></li></ol><h5 id="项目路线图建议" tabindex="-1">项目路线图建议 <a class="header-anchor" href="#项目路线图建议" aria-label="Permalink to &quot;项目路线图建议&quot;">​</a></h5><p>【补充内容】推荐的开发优先级：</p><ol><li><strong>第一阶段 (核心体验)</strong>：实现基于Video.js的单视频播放器，验证服务器Range请求与拖拽功能。</li><li><strong>第二阶段 (核心交互)</strong>：开发上下滑动的容器组件，实现视频的切换逻辑与基本预加载。</li><li><strong>第三阶段 (优化与扩展)</strong>：完善UI细节（加载状态、错误处理）、用户系统（点赞、收藏）、剧集选择等功能。</li><li><strong>未来考量</strong>：若后端支持HLS/DASH等流媒体协议，可通过Video.js平滑升级至自适应码率播放。</li></ol>',28)])])}const f=e(i,[["render",r]]);export{p as __pageData,f as default};
